import type { Consult, ConsultKind, ConsultChannel } from "@/lib/consult/types";
import { summarizeConsult, stampFor } from "@/lib/consult/summarize";
import { clients } from "@/lib/mock/clients";
import { seededRandom, absolute } from "@/lib/utils";

/**
 * Seeded consult history.
 *
 * The raw notes below are written the way coaches actually type mid-conversation
 * — fragments, shorthand, no punctuation discipline. That is deliberate: the
 * summarizer has to earn its keep on realistic input, and a demo that only works
 * on tidy prose proves nothing.
 *
 * Summaries are generated by running the real summarizer over these notes at
 * module load, so what the demo displays is genuinely the engine's output, not
 * hand-written text pretending to be.
 */

