const NOW_MS = absolute("2026-06-12T09:00:00").getTime();

function buildConsult(
  clientId: string,
  authorId: string,
  template: (typeof NOTE_TEMPLATES)[number],
  index: number,
  daysAgo: number,
  signed: boolean,
): Consult {
  const startedAt = absolute(NOW_MS - daysAgo * 86_400_000).toISOString();
  const summary = summarizeConsult(template.notes);
  const provenance = stampFor(template.notes, startedAt);

  return {
    id: `con-${clientId.slice(-3)}-${index}`,
    clientId,
    authorId,
    kind: template.kind,
    channel: template.channel,
    status: signed ? "Signed" : "Awaiting review",
    startedAt,
    endedAt: startedAt,
    durationMin: template.channel === "Messaging" ? 4 : template.channel === "Phone" ? 12 : 35,
    rawNotes: template.notes,
    aiSummary: summary,
    aiProvenance: provenance,
    // A signed consult's final summary is the AI's, accepted as-is unless the
    // coach edited it — editedFields() surfaces the difference in the UI.
    finalSummary: signed ? summary : undefined,
    signedAt: signed ? startedAt : undefined,
    signedBy: signed ? authorId : undefined,
    addenda: [],
    visibleToClient: signed,
  };
}

export const consults: Consult[] = clients.flatMap((c) => {
  const rand = seededRandom(c.id + "consults");
  // Roughly: active members have a richer consult history than leads.
  const count =
    c.status === "Active Protocol" || c.status === "Follow-Up Due"
      ? 2 + Math.floor(rand() * 3)
      : c.status === "Lead"
        ? 0
        : 1 + Math.floor(rand() * 2);

  return Array.from({ length: count }, (_, i) => {
    const template = NOTE_TEMPLATES[Math.floor(rand() * NOTE_TEMPLATES.length)];
    const daysAgo = 4 + i * 28 + Math.floor(rand() * 10);
    // The most recent consult on some members is deliberately left unsigned so
    // the review queue has real work in it.
    const signed = i > 0 || rand() > 0.28;
    return buildConsult(c.id, c.coachId, template, i + 1, daysAgo, signed);
  });
});

export const consultsByClient: Record<string, Consult[]> = consults.reduce(
  (acc, c) => {
    (acc[c.clientId] ??= []).push(c);
    return acc;
  },
  {} as Record<string, Consult[]>,
);

/** Newest first — how every surface displays them. */
export function consultsForClient(clientId: string): Consult[] {
  return [...(consultsByClient[clientId] ?? [])].sort((a, b) =>
    b.startedAt.localeCompare(a.startedAt),
  );
}

export function latestConsult(clientId: string): Consult | undefined {
  return consultsForClient(clientId)[0];
}

/** Consults a coach still owes a signature on. Drives the coach's Today queue. */
export function unsignedConsultsFor(coachId: string): Consult[] {
  return consults
    .filter((c) => c.authorId === coachId && c.status !== "Signed")
    .sort((a, b) => b.startedAt.localeCompare(a.startedAt));
}

export const NOTE_TEMPLATE_SAMPLES = NOTE_TEMPLATES.map((t) => t.notes);
